1521   ///
1522   /// This method contains the mechanics of fusing two loops, represented by \p
1523   /// FC0 and \p FC1. It is assumed that \p FC0 dominates \p FC1 and \p FC1
1524   /// postdominates \p FC0 (making them control flow equivalent). It also
1525   /// assumes that the other conditions for fusion have been met: adjacent,
1526   /// identical trip counts, and no negative distance dependencies exist that
1527   /// would prevent fusion. Thus, there is no checking for these conditions in
1528   /// this method.
1529   ///
1530   /// Fusion is performed by rewiring the CFG to update successor blocks of the
1531   /// components of tho loop. Specifically, the following changes are done:
1532   ///
1533   ///   1. The preheader of \p FC1 is removed as it is no longer necessary
1534   ///   (because it is currently only a single statement block).
1535   ///   2. The latch of \p FC0 is modified to jump to the header of \p FC1.
1536   ///   3. The latch of \p FC1 i modified to jump to the header of \p FC0.
1537   ///   4. All blocks from \p FC1 are removed from FC1 and added to FC0.
1538   ///
1539   /// All of these modifications are done with dominator tree updates, thus
1540   /// keeping the dominator (and post dominator) information up-to-date.
1541   ///
1542   /// This can be improved in the future by actually merging blocks during
1543   /// fusion. For example, the preheader of \p FC1 can be merged with the
1544   /// preheader of \p FC0. This would allow loops with more than a single
1545   /// statement in the preheader to be fused. Similarly, the latch blocks of the
1546   /// two loops could also be fused into a single block. This will require
1547   /// analysis to prove it is safe to move the contents of the block past
1548   /// existing code, which currently has not been implemented.
1549   Loop *performFusion(const FusionCandidate &FC0, const FusionCandidate &FC1) {
1550     assert(FC0.isValid() && FC1.isValid() &&
1551            "Expecting valid fusion candidates");
1552 
1553     LLVM_DEBUG(dbgs() << "Fusion Candidate 0: \n"; FC0.dump();
1554                dbgs() << "Fusion Candidate 1: \n"; FC1.dump(););
1555 
1556     // Move instructions from the preheader of FC1 to the end of the preheader
1557     // of FC0.
1558     moveInstructionsToTheEnd(*FC1.Preheader, *FC0.Preheader, DT, PDT, DI);
1559 
1560     // Fusing guarded loops is handled slightly differently than non-guarded
1561     // loops and has been broken out into a separate method instead of trying to
1562     // intersperse the logic within a single method.
1563     if (FC0.GuardBranch)
1564       return fuseGuardedLoops(FC0, FC1);
1565 
1566     assert(FC1.Preheader ==
1567            (FC0.Peeled ? FC0.ExitBlock->getUniqueSuccessor() : FC0.ExitBlock));
1568     assert(FC1.Preheader->size() == 1 &&
1569            FC1.Preheader->getSingleSuccessor() == FC1.Header);
1570 
1571     // Remember the phi nodes originally in the header of FC0 in order to rewire
1572     // them later. However, this is only necessary if the new loop carried
1573     // values might not dominate the exiting branch. While we do not generally
1574     // test if this is the case but simply insert intermediate phi nodes, we
1575     // need to make sure these intermediate phi nodes have different
1576     // predecessors. To this end, we filter the special case where the exiting
1577     // block is the latch block of the first loop. Nothing needs to be done
1578     // anyway as all loop carried values dominate the latch and thereby also the
